  "Sem jogos de {name}": { en: "No {name} games", es: "Sin juegos de {name}", fr: "Aucun jeu {name}", zh: "没有 {name} 游戏", ru: "Нет игр {name}" },
  "Escolha uma pasta SÓ pra {name} — assim cada emulador pode ter a sua. O Ludex detecta as ROMs pela extensão.": { en: "Choose a folder ONLY for {name} — so each emulator can have its own. Ludex detects ROMs by extension.", es: "Elige una carpeta SOLO para {name} — así cada emulador puede tener la suya. Ludex detecta las ROMs por la extensión.", fr: "Choisissez un dossier UNIQUEMENT pour {name} — ainsi chaque émulateur peut avoir le sien. Ludex détecte les ROMs par l'extension.", zh: "仅为 {name} 选择一个文件夹——这样每个模拟器都能有自己的文件夹。Ludex 按扩展名检测 ROM。", ru: "Выберите папку ТОЛЬКО для {name} — так у каждого эмулятора будет своя. Ludex определяет ROM по расширению." },
