  "Você usou os {n} dias da versão Android gratuita. Pra continuar, compre a versão Windows.": { en: "You've used the {n} days of the free Android version. To continue, buy the Windows version.", es: "Usaste los {n} días de la versión Android gratuita. Para continuar, compra la versión Windows.", fr: "Vous avez utilisé les {n} jours de la version Android gratuite. Pour continuer, achetez la version Windows.", zh: "你已用完免费 Android 版本的 {n} 天。要继续，请购买 Windows 版本。", ru: "Вы использовали {n} дней бесплатной версии для Android. Чтобы продолжить, купите версию для Windows." },
  "Falha no layout: {e}": { en: "Layout failed: {e}", es: "Error en el diseño: {e}", fr: "Échec de la disposition : {e}", zh: "布局失败：{e}", ru: "Сбой раскладки: {e}" },
  "Sistema \"{name}\" sem core libretro": { en: "System \"{name}\" has no libretro core", es: "Sistema \"{name}\" sin core libretro", fr: "Système « {name} » sans core libretro", zh: "系统\"{name}\"没有 libretro 核心", ru: "У системы «{name}» нет ядра libretro" },
  "Salvo no slot {slot}": { en: "Saved to slot {slot}", es: "Guardado en el slot {slot}", fr: "Enregistré dans l'emplacement {slot}", zh: "已保存到槽位 {slot}", ru: "Сохранено в слот {slot}" },
  "Carregado slot {slot}": { en: "Loaded slot {slot}", es: "Cargado slot {slot}", fr: "Emplacement {slot} chargé", zh: "已加载槽位 {slot}", ru: "Загружен слот {slot}" },
  "Falha ao carregar: {e}": { en: "Failed to load: {e}", es: "Error al cargar: {e}", fr: "Échec du chargement : {e}", zh: "加载失败：{e}", ru: "Не удалось загрузить: {e}" },
  "Pausado (30min sem input). Toque pra retomar.": { en: "Paused (30min without input). Tap to resume.", es: "Pausado (30min sin actividad). Toca para reanudar.", fr: "En pause (30min sans saisie). Touchez pour reprendre.", zh: "已暂停（30 分钟无操作）。点击以继续。", ru: "Пауза (30 мин без ввода). Нажмите, чтобы продолжить." },
  "Screenshot salva (Ajustes -> Galeria)": { en: "Screenshot saved (Settings -> Gallery)", es: "Captura guardada (Ajustes -> Galería)", fr: "Capture enregistrée (Réglages -> Galerie)", zh: "截图已保存（设置 -> 图库）", ru: "Скриншот сохранён (Настройки -> Галерея)" },
  "Erro ao carregar jogo": { en: "Error loading game", es: "Error al cargar el juego", fr: "Erreur de chargement du jeu", zh: "加载游戏出错", ru: "Ошибка загрузки игры" },
  "Provável: BIOS do sistema falta em Ludex/system/.": { en: "Likely: system BIOS missing in Ludex/system/.", es: "Probable: falta la BIOS del sistema en Ludex/system/.", fr: "Probable : le BIOS du système manque dans Ludex/system/.", zh: "可能：Ludex/system/ 中缺少系统 BIOS。", ru: "Вероятно: отсутствует BIOS системы в Ludex/system/." },
  "Provável: BIOS ou config inválida do core.": { en: "Likely: invalid core BIOS or config.", es: "Probable: BIOS o config del core inválida.", fr: "Probable : BIOS ou config du core invalide.", zh: "可能：核心 BIOS 或配置无效。", ru: "Вероятно: неверный BIOS или конфигурация ядра." },
  "Vá em Ajustes → Procurar BIOS no celular inteiro.": { en: "Go to Settings → Search the whole phone for BIOS.", es: "Ve a Ajustes → Buscar BIOS en todo el celular.", fr: "Allez dans Réglages → Chercher des BIOS sur tout le téléphone.", zh: "前往设置 → 在整部手机中搜索 BIOS。", ru: "Перейдите в Настройки → Искать BIOS на всём телефоне." },
  "Importei {n} BIOS. Tente abrir o jogo de novo.": { en: "Imported {n} BIOS. Try opening the game again.", es: "Importé {n} BIOS. Intenta abrir el juego de nuevo.", fr: "{n} BIOS importés. Réessayez d'ouvrir le jeu.", zh: "已导入 {n} 个 BIOS。请再次尝试打开游戏。", ru: "Импортировано BIOS: {n}. Попробуйте открыть игру снова." },
  "Nenhuma BIOS encontrada no storage. Coloque os .bin em Download e tente novamente.": { en: "No BIOS found in storage. Put the .bin files in Download and try again.", es: "No se encontró BIOS en el almacenamiento. Coloca los .bin en Download e inténtalo de nuevo.", fr: "Aucun BIOS trouvé dans le stockage. Placez les .bin dans Download et réessayez.", zh: "存储中未找到 BIOS。请将 .bin 文件放入 Download 并重试。", ru: "BIOS не найден в хранилище. Поместите файлы .bin в Download и повторите." },
  "Procurar BIOS agora": { en: "Search BIOS now", es: "Buscar BIOS ahora", fr: "Chercher des BIOS maintenant", zh: "立即搜索 BIOS", ru: "Искать BIOS сейчас" },
  "Core libretro {core} não está dentro do APK pra este sistema no Android. Suporte vai chegar em versão futura — por enquanto use o launcher no PC.": { en: "The libretro core {core} isn't bundled in the APK for this system on Android. Support will arrive in a future version — for now use the PC launcher.", es: "El core libretro {core} no está dentro del APK para este sistema en Android. El soporte llegará en una versión futura — por ahora usa el launcher en PC.", fr: "Le core libretro {core} n'est pas inclus dans l'APK pour ce système sur Android. Le support arrivera dans une version future — pour l'instant utilisez le launcher PC.", zh: "Android 上此系统的 libretro 核心 {core} 未包含在 APK 中。未来版本将支持——目前请使用 PC 启动器。", ru: "Ядро libretro {core} не входит в APK для этой системы на Android. Поддержка появится в будущей версии — пока используйте лаунчер на ПК." },
