  "Tap duplo: save state 0": { en: "Double tap: save state 0", es: "Toque doble: guardar estado 0", fr: "Double tap : sauvegarde d'état 0", zh: "双击：即时存档 0", ru: "Двойное касание: сохранение 0" },
