  "Versão prévia — a versão Desktop tem mais consoles": { en: "Preview version — the Desktop version has more consoles", es: "Versión previa — la versión de escritorio tiene más consolas", fr: "Version préliminaire — la version Bureau a plus de consoles", zh: "预览版——桌面版支持更多主机", ru: "Превью-версия — в версии для ПК больше консолей" },
