  "Resolução, Performance, etc": { en: "Resolution, Performance, etc", es: "Resolución, rendimiento, etc", fr: "Résolution, performances, etc", zh: "分辨率、性能等", ru: "Разрешение, производительность и т.д." },
  "Mudanças aplicam ao abrir o jogo de novo.": { en: "Changes apply when you open the game again.", es: "Los cambios se aplican al abrir el juego de nuevo.", fr: "Les changements s'appliquent à la prochaine ouverture du jeu.", zh: "更改将在下次打开游戏时生效。", ru: "Изменения применяются при повторном открытии игры." },
  "Buscar / gerenciar cheats": { en: "Search / manage cheats", es: "Buscar / gestionar trucos", fr: "Rechercher / gérer les codes", zh: "搜索 / 管理金手指", ru: "Искать / управлять читами" },
