  "Continue onde parou": { en: "Continue where you left off", es: "Continúa donde lo dejaste", fr: "Reprenez où vous en étiez", zh: "继续上次进度", ru: "Продолжить с того же места" },
  "Passo {n} de {total}": { en: "Step {n} of {total}", es: "Paso {n} de {total}", fr: "Étape {n} sur {total}", zh: "第 {n} 步，共 {total} 步", ru: "Шаг {n} из {total}" },
