  "Marcou 1 jogo como zerado": { en: "Marked 1 game as beaten", es: "Marcó 1 juego como completado", fr: "A marqué 1 jeu comme terminé", zh: "将1款游戏标记为通关", ru: "Отметил 1 игру как пройденную" },
