  "Primeiro Jogo": { en: "First Game", es: "Primer Juego", fr: "Premier Jeu", zh: "首款游戏", ru: "Первая игра" },
  "Sistema sem base de cheats online — adicione manualmente.": { en: "System with no online cheat database — add them manually.", es: "Sistema sin base de datos de trucos en línea — agrégalos manualmente.", fr: "Système sans base de données de cheats en ligne — ajoutez-les manuellement.", zh: "该系统没有在线金手指数据库——请手动添加。", ru: "Для этой системы нет онлайн-базы читов — добавьте их вручную." },
